sql:
SELECT storm_id, MAX(wind_speed) AS max_wind_speed
FROM storm_data
GROUP BY storm_id;

SELECT COUNT(DISTINCT sd.source_id) AS unique_data_sources
FROM storm_data sd
WHERE sd.source_id IN (SELECT source_id FROM data_sources);

SELECT (
    SELECT COUNT(*) 
    FROM storms 
    WHERE initial_status <> final_status
) * 100.0 / 
(
    SELECT COUNT(*) 
    FROM storms
) AS percentage;

